#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0;
        for(int i=0;i<N;++i){
            long long x; scanf("%lld", &x);
            sum += x;
        }
        long long r = (long long)sqrt((double)sum);
        if(r*r == sum) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

