const fs = require('fs');
const input = fs.readFileSync(0, 'utf8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let results = [];
function isPerfectSquare(n) {
  let low = 0n, high = n;
  while (low <= high) {
    const mid = (low + high) >> 1n;
    const sq = mid * mid;
    if (sq === n) return true;
    if (sq < n) low = mid + 1n;
    else high = mid - 1n;
  }
  return false;
}
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  let sum = 0n;
  for (let i = 0; i < N; ++i) {
    sum += BigInt(input[idx++]);
  }
  results.push(isPerfectSquare(sum) ? 'Yes' : 'No');
}
console.log(results.join('\n'));
